class Node:
    def __init__(self, data):
        self.data = data
        self.next = None
        self.prev = None

class Queue:
    def __init__(self):
        self.front = None
        self.rear = None

    def checkEmpty(self):
        return self.front == self.rear

    def enqueue(self, value):
        newNode = Node(value)
        if self.rear:
            self.rear.next = newNode
            newNode.prev = self.rear
            self.rear = newNode
        else:
            self.front = self.rear = newNode

    def dequeue(self, operation):
        if operation == 0:
            if not self.front:
                return None
            tmp = self.front.data
            self.front = self.front.next
            if not self.front:
                self.rear = None
            return tmp
        elif operation == 1:
            if not self.rear:
                return None
            tmp = self.rear.data
            self.rear = self.rear.prev
            if not self.rear:
                self.front = None
            return tmp
        else:
            raise ValueError("Invalid operation")

    def __iter__(self):
        node = self.front
        while node:
            yield node.data
            node = node.next

    def __str__(self):
        return str(list(self))

    def __repr__(self):
        return str(list(self))


if __name__ == '__main__':
    q = Queue()
    print(q.checkEmpty())  # True
    q.enqueue(1)
    q.enqueue(2)
    print(q.checkEmpty())  # False
    print(q.dequeue(0))  # 1
    print(q.dequeue(1))  # 2

