class Queue {
 public:
    bool checkEmpty();
    void enqueue(int value);
    int dequeue(int operation);
 private:
    class Node {
        int data;
        Node* next;
        Node* prev;
    };
    Node* front;
    Node* rear;
};

bool Queue::checkEmpty() {
    return front == rear;
}

void Queue::enqueue(int value) {
    Node* newNode = new Node(value);
    if (rear) {
        rear->next = newNode;
        newNode->prev = rear;
        rear = newNode;
    } else {
        front = rear = newNode;
    }
}

int Queue::dequeue(int operation) {
    if (operation == 0) {
        if (!front) {
            return -1;
        } else {
            int tmp = front->data;
            front = front->next;
            if (!front) {
                rear = nullptr;
            }
            return tmp;
        }
    } else if (operation == 1) {
        if (!rear) {
            return -1;
        } else {
            int tmp = rear->data;
            rear = rear->prev;
            if (!rear) {
                front = nullptr;
            }
            return tmp;
        }
    } else {
        throw std::invalid_argument("Invalid operation");
    }
}

int main() {
    Queue q;
    std::cout << std::boolalpha << q.checkEmpty() << std::endl;  // True
    q.enqueue(1);
    q.enqueue(2);
    std::cout << std::boolalpha << q.checkEmpty() << std::endl;  // False
    std::cout << q.dequeue(0) << std::endl;  // 1
    std::cout << q.dequeue(1) << std::endl;  // 2
    return 0;
}
